function showToast(message, type = 'success') { let container = document.getElementById('toast-container'); if (!container) { container = document.createElement('div'); container.id = 'toast-container'; container.className = 'toast-container'; document.body.appendChild(container); } const toast = document.createElement('div'); toast.className = `toast-item ${type}`; let iconClass = 'fa-check-circle'; if (type === 'error') { iconClass = 'fa-exclamation-circle'; } else if (type === 'info') { iconClass = 'fa-info-circle'; } toast.innerHTML = ` <i class="fas ${iconClass}"></i> <span>${message}</span> `; container.appendChild(toast); setTimeout(() => { toast.classList.add('show'); }, 50); setTimeout(() => { toast.classList.remove('show'); setTimeout(() => { toast.remove(); }, 300); }, 4000); } document.addEventListener('DOMContentLoaded', () => { const overlay = document.createElement('div'); overlay.className = 'command-palette-overlay'; overlay.id = 'command-palette-overlay'; overlay.setAttribute('role', 'dialog'); overlay.setAttribute('aria-modal', 'true'); overlay.setAttribute('aria-label', 'Command Palette Search'); overlay.innerHTML = ` <div class="command-palette"> <div class="command-palette-header"> <i class="fas fa-search"></i> <input type="text" class="command-palette-input" id="command-palette-input" placeholder="Search news portal... (Arrow keys to navigate, Esc to close)" autocomplete="off"> </div> <div class="command-palette-results" id="command-palette-results" role="listbox"> <div class="command-item empty-state">Type to begin searching...</div> </div> </div> `; document.body.appendChild(overlay); const input = document.getElementById('command-palette-input'); const resultsContainer = document.getElementById('command-palette-results'); let selectedIndex = -1; let debounceTimer = null; document.addEventListener('keydown', (e) => { if ((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); togglePalette(); } }); overlay.addEventListener('click', (e) => { if (e.target === overlay) { closePalette(); } }); input.addEventListener('keydown', (e) => { const items = resultsContainer.querySelectorAll('.command-item:not(.empty-state)'); if (e.key === 'Escape') { closePalette(); } else if (e.key === 'ArrowDown') { e.preventDefault(); if (items.length > 0) { selectedIndex = (selectedIndex + 1) % items.length; updateSelection(items); } } else if (e.key === 'ArrowUp') { e.preventDefault(); if (items.length > 0) { selectedIndex = (selectedIndex - 1 + items.length) % items.length; updateSelection(items); } } else if (e.key === 'Enter') { e.preventDefault(); if (selectedIndex >= 0 && items[selectedIndex]) { items[selectedIndex].click(); } } }); input.addEventListener('input', () => { clearTimeout(debounceTimer); const query = input.value.trim(); if (query === '') { resultsContainer.innerHTML = '<div class="command-item empty-state">Type to begin searching...</div>'; return; } debounceTimer = setTimeout(() => { fetchResults(query); }, 200); }); function togglePalette() { overlay.classList.toggle('open'); if (overlay.classList.contains('open')) { input.focus(); input.value = ''; resultsContainer.innerHTML = '<div class="command-item empty-state">Type to begin searching...</div>'; selectedIndex = -1; } } function closePalette() { overlay.classList.remove('open'); input.blur(); } function updateSelection(items) { items.forEach((item, index) => { if (index === selectedIndex) { item.classList.add('selected'); item.setAttribute('aria-selected', 'true'); item.scrollIntoView({ block: 'nearest' }); } else { item.classList.remove('selected'); item.setAttribute('aria-selected', 'false'); } }); } function fetchResults(query) { fetch((window.APP_URL || '') + `/search.php?q=${encodeURIComponent(query)}&ajax=1`) .then(res => res.json()) .then(data => { resultsContainer.innerHTML = ''; selectedIndex = -1; if (data.length === 0) { resultsContainer.innerHTML = '<div class="command-item empty-state">No matching articles found.</div>'; return; } data.forEach((article, idx) => { const item = document.createElement('div'); item.className = 'command-item'; item.setAttribute('role', 'option'); item.setAttribute('id', `option-${idx}`); item.innerHTML = ` <i class="far fa-file-alt"></i> <span>${escapeHtml(article.title)}</span> `; item.addEventListener('click', () => { window.location.href = (window.APP_URL || '') + `/news/${article.id}/${slugify(article.title)}`; }); resultsContainer.appendChild(item); }); }) .catch(() => { resultsContainer.innerHTML = '<div class="command-item empty-state error">Search error. Please try again.</div>'; }); } function escapeHtml(str) { return str.replace(/&/g, '&amp;') .replace(/</g, '&lt;') .replace(/>/g, '&gt;') .replace(/"/g, '&quot;') .replace(/'/g, '&#039;'); } function slugify(text) { return text.toString().toLowerCase() .replace(/\s+/g, '-') .replace(/[^\w\-]+/g, '') .replace(/\-\-+/g, '-') .replace(/^-+/, '') .replace(/-+$/, ''); } }); document.addEventListener('DOMContentLoaded', () => { initThemeManager(); setupHeaderDateTime(); setupMobileMenuDrawer(); setupImageLightbox(); setupScrollToTop(); registerServiceWorker(); }); function initThemeManager() { const themeToggleBtn = document.getElementById('theme-toggle'); const cookieName = 'theme_preference'; let currentTheme = getCookie(cookieName) || 'system'; applyTheme(currentTheme); if (themeToggleBtn) { themeToggleBtn.addEventListener('click', () => { let nextTheme = 'light'; if (currentTheme === 'light') { nextTheme = 'dark'; } else if (currentTheme === 'dark') { nextTheme = 'system'; } currentTheme = nextTheme; setCookie(cookieName, nextTheme, 365); applyTheme(nextTheme); let label = 'System preference'; if (nextTheme === 'light') label = 'Light theme'; if (nextTheme === 'dark') label = 'Dark theme'; if (typeof showToast === 'function') { showToast(`Theme changed to: ${label}`, 'info'); } }); } } function applyTheme(theme) { const btn = document.getElementById('theme-toggle'); const rootEl = document.documentElement; const bodyEl = document.body; if (theme === 'system') { bodyEl.setAttribute('data-theme-mode', 'system'); bodyEl.removeAttribute('data-theme'); rootEl.setAttribute('data-theme-mode', 'system'); rootEl.removeAttribute('data-theme'); if (btn) btn.innerHTML = '<i class="fas fa-desktop"></i>'; } else { bodyEl.setAttribute('data-theme-mode', 'fixed'); bodyEl.setAttribute('data-theme', theme); rootEl.setAttribute('data-theme-mode', 'fixed'); rootEl.setAttribute('data-theme', theme); if (btn) btn.innerHTML = theme === 'dark' ? '<i class="fas fa-sun"></i>' : '<i class="fas fa-moon"></i>'; } } function setupHeaderDateTime() { const dateContainer = document.getElementById('current-date'); if (dateContainer) { const fmt = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }; dateContainer.innerHTML = `<i class="far fa-calendar-alt"></i> ${new Date().toLocaleDateString('en-US', fmt)}`; } } function setupMobileMenuDrawer() { const trigger = document.getElementById('mobile-menu-toggle'); const drawer = document.getElementById('nav-links-menu'); if (trigger && drawer) { trigger.addEventListener('click', () => { drawer.classList.toggle('active'); trigger.innerHTML = drawer.classList.contains('active') ? '✕' : '☰'; }); document.addEventListener('click', (e) => { if (!trigger.contains(e.target) && !drawer.contains(e.target)) { drawer.classList.remove('active'); trigger.innerHTML = '☰'; } }); } } function setupImageLightbox() { const modal = document.getElementById('image-lightbox-modal'); const modalImg = document.getElementById('lightbox-zoom-img'); const modalCaption = document.getElementById('lightbox-zoom-caption'); const closeBtn = document.getElementById('lightbox-close-btn'); if (!modal || !modalImg) return; if (closeBtn) { closeBtn.addEventListener('click', () => { modal.style.display = 'none'; modal.setAttribute('aria-hidden', 'true'); }); } document.body.addEventListener('click', (e) => { const clickableImg = e.target.closest('.article-img-wrap img, .media-thumb img, .trending-item img, .section-static-banner img, .news-card-img'); if (clickableImg && !e.target.closest('.media-manager-item')) { modal.style.display = 'flex'; modal.setAttribute('aria-hidden', 'false'); modalImg.src = clickableImg.src; if (modalCaption) { modalCaption.textContent = clickableImg.alt || 'Palghar LIVE Preview'; } } }); } function setupScrollToTop() { const btn = document.getElementById('scroll-to-top-btn'); if (!btn) return; window.addEventListener('scroll', () => { if (window.scrollY > 300) { btn.classList.add('show'); } else { btn.classList.remove('show'); } }); btn.addEventListener('click', () => { window.scrollTo({ top: 0, behavior: 'smooth' }); }); } function registerServiceWorker() { if ('serviceWorker' in navigator) { navigator.serviceWorker.register((window.APP_URL || '') + '/service-worker.js') .then(() => console.log('Palghar LIVE Service Worker registered.')) .catch(err => console.log('SW registration failure:', err)); } } function setCookie(name, value, days) { let expires = ""; if (days) { let date = new Date(); date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000)); expires = "; expires=" + date.toUTCString(); } document.cookie = name + "=" + (value || "") + expires + "; path=/; SameSite=Lax"; } function getCookie(name) { let nameEQ = name + "="; let ca = document.cookie.split(';'); for(let i=0;i < ca.length;i++) { let c = ca[i]; while (c.charAt(0)==' ') c = c.substring(1,c.length); if (c.indexOf(nameEQ) == 0) return c.substring(nameEQ.length,c.length); } return null; }